#include<bits/stdc++.h>
using namespace std;
int p[200010];
struct node
{
    int l,d;
    bool operator<(const node&b)const
    {
        return l<b.l;
    }
}a[200010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&p[i]);
    }
    sort(p+1,p+1+n);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i].l);
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i].d);
    }
    priority_queue<int> q;
    sort(a+1,a+1+m);
    int j=1;
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        while(j<=m&&a[j].l<=p[i])
        {
            q.push(a[j].d);
            j++;
        }
        int tmp=p[i];
        if(!q.empty())
        {
            tmp-=q.top();
            q.pop();
        }
        ans+=tmp;
    }
    printf("%lld",ans);
    return 0;
}
